FIXTURES.NextFixture = (function NextFixture() {

  var container = document.querySelector('.next-fixture-container');
  var nextFixtureTemplate = document.getElementById('next-fixture-template');

  function setNextFixture(fixture) {
    var nextFixtureEl = nextFixtureTemplate.content.cloneNode(true);
    nextFixtureEl.querySelector('.next-opposition-label').innerText = fixture.opponent;
    var kickoff = dateFormat(new Date(fixture.kickoff), "ddd, yyyy mmmm dd, HH:MM");
    nextFixtureEl.querySelector('.next-kickoff-label').innerText = kickoff;
    nextFixtureEl.querySelector('.next-competition-label').innerText = fixture.competition;
    console.log(fixture);
    container.appendChild(nextFixtureEl);
  }

  return {
    setNextFixture: setNextFixture
  }

}());
